//
// Badges
// --------------------------------------------------


// Base class
.badge {
  display: inline-block;
  min-width: 10px;
  padding: 3px 7px;
  font-size: $font-size-small;
  font-weight: $badge-font-weight;
  line-height: $badge-line-height;
  color: $badge-color;
  text-align: center;
  white-space: nowrap;
  vertical-align: middle;
  background-color: $badge-bg;
  border-radius: $badge-border-radius;

  // Empty badges collapse automatically (not available in IE8)
  &:empty {
    display: none;
  }

  // Quick fix for badges in buttons
  .btn & {
    position: relative;
    top: -1px;
  }

  .btn-xs &,
  .btn-group-xs > .btn & {
    top: 0;
    padding: 1px 5px;
  }

  // [converter] extracted a& to a.badge

  // Account for badges in navs
  .list-group-item.active > &,
  .nav-pills > .active > a > & {
    color: $badge-active-color;
    background-color: $badge-active-bg;
  }

  .list-group-item > & {
    float: right;
  }

  .list-group-item > & + & {
    margin-right: 5px;
  }

  .nav-pills > li > a > & {
    margin-left: 3px;
  }
}

// Hover state, but only for links
a.badge {
  &:hover,
  &:focus {
    color: $badge-link-hover-color;
    text-decoration: none;
    cursor: pointer;
  }
}

@use "bulma/sass/utilities/css-variables" as cv;
@use "bulma/sass/utilities/mixins" as mixins;

.docs-navbar.navbar {
    &.is-transparent {
        box-shadow: cv.getVar('shadow');
    }

    &.is-scrolled {
        backdrop-filter: blur(12px) saturate(180%);
        background: rgba(255, 255, 255, 0.85) !important;
        box-shadow: var(--shadow-sm);
    }

    [data-theme="dark"] &.is-scrolled {
        background: rgba(28, 23, 40, 0.88) !important;
    }

    .navbar-cta {
        display: inline-flex;
        align-items: center;
        background: var(--color-brand);
        color: #fff !important;
        border-radius: 6px;
        padding: 8px 18px;
        font-size: var(--text-sm);
        font-weight: 600;
        text-decoration: none;
        transition:
            background var(--duration-normal) var(--ease-out),
            box-shadow var(--duration-normal) var(--ease-out);

        &:hover {
            background: var(--color-brand-dark) !important;
            box-shadow: var(--shadow-brand);
        }
    }

    .is-version {
        flex-direction: column;
        align-items: flex-start;
    }

    .navbar-item {
        img {
            max-height: 2rem;
        }
    }

    .has-dropdown > .navbar-link {
        cursor: default;
        @include mixins.unselectable;
    }

    .navbar-dropdown {
        .navbar-item {
            display: flex;
            .navbar-item-text {
                flex: 1;
            }
        }
        .is-subitem {
            text-transform: uppercase;
            color: cv.getVar('grey');
            &:not(:first-child) {
                margin-top: 1rem;
            }
        }
    }
}

// Avatars
.avatar {
  @include avatar-base();
  background: $primary-color;
  border-radius: 50%;
  color: rgba($light-color, .85);
  display: inline-block;
  font-weight: 300;
  line-height: 1.25;
  margin: 0;
  position: relative;
  vertical-align: middle;

  &.avatar-xs {
    @include avatar-base($unit-4);
  }
  &.avatar-sm {
    @include avatar-base($unit-6);
  }
  &.avatar-lg {
    @include avatar-base($unit-12);
  }
  &.avatar-xl {
    @include avatar-base($unit-16);
  }

  img {
    border-radius: 50%;
    height: 100%;
    position: relative;
    width: 100%;
    z-index: $zindex-0;
  }

  .avatar-icon,
  .avatar-presence {
    background: $bg-color-light;
    bottom: 14.64%;
    height: 50%;
    padding: $border-width-lg;
    position: absolute;
    right: 14.64%;
    transform: translate(50%, 50%);
    width: 50%;
    z-index: $zindex-0 + 1;
  }

  .avatar-presence {
    background: $gray-color;
    box-shadow: 0 0 0 $border-width-lg $light-color;
    border-radius: 50%;
    height: .5em;
    width: .5em;

    &.online {
      background: $success-color;
    }

    &.busy {
      background: $error-color;
    }

    &.away {
      background: $warning-color;
    }
  }

  &[data-initial]::before {
    color: currentColor;
    content: attr(data-initial);
    left: 50%;
    position: absolute;
    top: 50%;
    transform: translate(-50%, -50%);
    z-index: $zindex-0;
  }
}

// Bars
.bar {
  background: $bg-color-dark;
  border-radius: $border-radius;
  display: flex;
  flex-wrap: nowrap;
  height: $unit-4;
  width: 100%;

  &.bar-sm {
    height: $unit-1;
  }

  // TODO: attr() support
  .bar-item {
    background: $primary-color;
    color: $light-color;
    display: block;
    font-size: $font-size-sm;
    flex-shrink: 0;
    line-height: $unit-4;
    height: 100%;
    position: relative;
    text-align: center;
    width: 0;

    &:first-child {
      border-bottom-left-radius: $border-radius;
      border-top-left-radius: $border-radius;
    }
    &:last-child {
      border-bottom-right-radius: $border-radius;
      border-top-right-radius: $border-radius;
      flex-shrink: 1;
    }
  }
}

// Slider bar
.bar-slider {
  height: $border-width-lg;
  margin: $layout-spacing 0;
  position: relative;

  .bar-item {
    left: 0;
    padding: 0;
    position: absolute;
    &:not(:last-child):first-child {
      background: $bg-color-dark;
      z-index: $zindex-0;
    }
  }

  .bar-slider-btn {
    background: $primary-color;
    border: 0;
    border-radius: 50%;
    height: $unit-3;
    padding: 0;
    position: absolute;
    right: 0;
    top: 50%;
    transform: translate(50%, -50%);
    width: $unit-3;

    &:active {
      box-shadow: 0 0 0 .1rem $primary-color;
    }
  }
}

// Modals
.modal {
  align-items: center;
  bottom: 0;
  display: none;
  justify-content: center;
  left: 0;
  opacity: 0;
  overflow: hidden;
  padding: $layout-spacing;
  position: fixed;
  right: 0;
  top: 0;

  &:target,
  &.active {
    display: flex;
    opacity: 1;
    z-index: $zindex-4;

    .modal-overlay {
      background: rgba($bg-color, .75);
      bottom: 0;
      cursor: default;
      display: block;
      left: 0;
      position: absolute;
      right: 0;
      top: 0;
    }

    .modal-container {
      animation: slide-down .2s ease 1;
      z-index: $zindex-0;
    }
  }

  &.modal-sm {
    .modal-container {
      max-width: $control-width-sm;
      padding: 0 $unit-2;
    }
  }

  &.modal-lg {
    .modal-overlay {
      background: $bg-color-light;
    }

    .modal-container {
      box-shadow: none;
      max-width: $control-width-lg;
    }
  }
}

.modal-container {
  @include shadow-variant(.2rem);
  background: $bg-color-light;
  border-radius: $border-radius;
  display: flex;
  flex-direction: column;
  max-height: 75vh;
  max-width: $control-width-md;
  padding: 0 $unit-4;
  width: 100%;

  &.modal-fullheight {
    max-height: 100vh;
  }

  .modal-header {
    color: $dark-color;
    padding: $unit-4;
  }

  .modal-body {
    overflow-y: auto;
    padding: $unit-4;
    position: relative;
  }

  .modal-footer {
    padding: $unit-4;
    text-align: right;
  }
}

// Steps
.step {
  display: flex;
  flex-wrap: nowrap;
  list-style: none;
  margin: $unit-1 0;
  width: 100%;

  .step-item {
    flex: 1 1 0;
    margin-top: 0;
    min-height: 1rem;
    text-align: center;
    position: relative;

    &:not(:first-child)::before {
      background: $primary-color;
      content: "";
      height: 2px;
      left: -50%;
      position: absolute;
      top: 9px;
      width: 100%;
    }

    a {
      color: $primary-color;
      display: inline-block;
      padding: 20px 10px 0;
      text-decoration: none;

      &::before {
        background: $primary-color;
        border: $border-width-lg solid $light-color;
        border-radius: 50%;
        content: "";
        display: block;
        height: $unit-3;
        left: 50%;
        position: absolute;
        top: $unit-1;
        transform: translateX(-50%);
        width: $unit-3;
        z-index: $zindex-0;
      }
    }

    &.active {
      a {
        &::before {
          background: $light-color;
          border: $border-width-lg solid $primary-color;
        }
      }

      & ~ .step-item {
        &::before {
          background: $border-color;
        }

        a {
          color: $gray-color;

          &::before {
            background: $border-color;
          }
        }
      }
    }
  }
}

// Tooltips
.tooltip {
  position: relative;
  &::after {
    background: rgba($dark-color, .95);
    border-radius: $border-radius;
    bottom: 100%;
    color: $light-color;
    content: attr(data-tooltip);
    display: block;
    font-size: $font-size-sm;
    left: 50%;
    max-width: $control-width-sm;
    opacity: 0;
    overflow: hidden;
    padding: $unit-1 $unit-2;
    pointer-events: none;
    position: absolute;
    text-overflow: ellipsis;
    transform: translate(-50%, $unit-2);
    transition: opacity .2s, transform .2s;
    white-space: pre;
    z-index: $zindex-3;
  }
  &:focus,
  &:hover {
    &::after {
      opacity: 1;
      transform: translate(-50%, -$unit-1);
    }
  }
  &[disabled],
  &.disabled {
    pointer-events: auto;
  }

  &.tooltip-right {
    &::after {
      bottom: 50%;
      left: 100%;
      transform: translate(-$unit-1, 50%);
    }
    &:focus,
    &:hover {
      &::after {
        transform: translate($unit-1, 50%);
      }
    }
  }

  &.tooltip-bottom {
    &::after {
      bottom: auto;
      top: 100%;
      transform: translate(-50%, -$unit-2);
    }
    &:focus,
    &:hover {
      &::after {
        transform: translate(-50%, $unit-1);
      }
    }
  }

  &.tooltip-left {
    &::after {
      bottom: 50%;
      left: auto;
      right: 100%;
      transform: translate($unit-2, 50%);
    }
    &:focus,
    &:hover {
      &::after {
        transform: translate(-$unit-1, 50%);
      }
    }
  }
}

@use "../utilities/initial-variables" as iv;

.#{iv.$class-prefix}marginless {
  margin: 0 !important;
}

.#{iv.$class-prefix}paddingless {
  padding: 0 !important;
}

$spacing-shortcuts: (
  "margin": "m",
  "padding": "p",
) !default;
$spacing-directions: (
  "top": "t",
  "right": "r",
  "bottom": "b",
  "left": "l",
) !default;
$spacing-horizontal: "x" !default;
$spacing-vertical: "y" !default;
$spacing-values: (
  "0": 0,
  "1": 0.25rem,
  "2": 0.5rem,
  "3": 0.75rem,
  "4": 1rem,
  "5": 1.5rem,
  "6": 3rem,
  "auto": auto,
) !default;

@each $property, $shortcut in $spacing-shortcuts {
  @each $name, $value in $spacing-values {
    // All directions
    .#{iv.$class-prefix}#{$shortcut}-#{$name} {
      #{$property}: $value !important;
    }

    // Cardinal directions
    @each $direction, $suffix in $spacing-directions {
      .#{iv.$class-prefix}#{$shortcut}#{$suffix}-#{$name} {
        #{$property}-#{$direction}: $value !important;
      }
    }

    // Horizontal axis
    @if $spacing-horizontal != null {
      .#{iv.$class-prefix}#{$shortcut}#{$spacing-horizontal}-#{$name} {
        #{$property}-left: $value !important;
        #{$property}-right: $value !important;
      }
    }

    // Vertical axis
    @if $spacing-vertical != null {
      .#{iv.$class-prefix}#{$shortcut}#{$spacing-vertical}-#{$name} {
        #{$property}-top: $value !important;
        #{$property}-bottom: $value !important;
      }
    }
  }
}

@use "../utilities/css-variables" as cv;
@use "../utilities/initial-variables" as iv;
@use "../utilities/extends";

$box-background-color: cv.getVar("scheme-main") !default;
$box-color: cv.getVar("text") !default;
$box-radius: cv.getVar("radius-large") !default;
$box-shadow: cv.getVar("shadow") !default;
$box-padding: 1.25rem !default;

$box-link-hover-shadow:
  0 0.5em 1em -0.125em hsla(#{cv.getVar("scheme-h")}, #{cv.getVar("scheme-s")}, #{cv.getVar(
          "scheme-invert-l"
        )}, 0.1),
  0 0 0 1px cv.getVar("link") !default;
$box-link-active-shadow:
  inset 0 1px 2px
    hsla(
      #{cv.getVar("scheme-h")},
      #{cv.getVar("scheme-s")},
      #{cv.getVar("scheme-invert-l")},
      0.2
    ),
  0 0 0 1px cv.getVar("link") !default;

.#{iv.$class-prefix}box {
  @include cv.register-vars(
    (
      "box-background-color": #{$box-background-color},
      "box-color": #{$box-color},
      "box-radius": #{$box-radius},
      "box-shadow": #{$box-shadow},
      "box-padding": #{$box-padding},
      "box-link-hover-shadow": #{$box-link-hover-shadow},
      "box-link-active-shadow": #{$box-link-active-shadow},
    )
  );
}

.#{iv.$class-prefix}box {
  @extend %block;
  background-color: cv.getVar("box-background-color");
  border-radius: cv.getVar("box-radius");
  box-shadow: cv.getVar("box-shadow");
  color: cv.getVar("box-color");
  display: block;
  padding: cv.getVar("box-padding");
}

a.#{iv.$class-prefix}box {
  &:hover,
  &:focus {
    box-shadow: cv.getVar("box-link-hover-shadow");
  }

  &:active {
    box-shadow: cv.getVar("box-link-active-shadow");
  }
}

//
// Component: Table
//

.table {
  &:not(.table-dark) {
    color: inherit;
  }

  // fixed table head
  // Uses Bootstrap CSS variables so the sticky header follows light/dark mode
  // automatically. Fixes #6026.
  &.table-head-fixed {
    thead tr:nth-child(1) th {
      position: sticky;
      top: 0;
      z-index: 10;
      background-color: var(--bs-body-bg, #{$white});
      border-bottom: 0;
      box-shadow: inset 0 1px 0 var(--bs-border-color, #{$table-border-color}), inset 0 -1px 0 var(--bs-border-color, #{$table-border-color});
    }
  }

  // no border
  &.no-border {
    &,
    td,
    th {
      border: 0;
    }
  }

  // .text-center in tables
  &.text-center {
    &,
    td,
    th {
      text-align: center;
    }
  }

  &.table-valign-middle {
    thead > tr > th,
    thead > tr > td,
    tbody > tr > th,
    tbody > tr > td {
      vertical-align: middle;
    }
  }

  .card-body.p-0 & {
    thead > tr > th,
    thead > tr > td,
    tfoot > tr > th,
    tfoot > tr > td,
    tbody > tr > th,
    tbody > tr > td {
      &:first-of-type {
        padding-left: map-get($spacers, 4);
      }

      &:last-of-type {
        padding-right: map-get($spacers, 4);
      }
    }
  }
}

@import "./radio";
@import "./radio.ios.vars";

// iOS Radio
// --------------------------------------------------

:host {
  --color-checked: #{ion-color(primary, base)};
}

:host(.ion-color.radio-checked) .radio-inner {
  border-color: current-color(base);
}

.item-radio.item-ios ion-label {
  @include margin-horizontal(0, null);
}

// iOS Radio Checkmark: Checked
// -----------------------------------------

.radio-inner {
  width: 33%;
  height: 50%;
}

:host(.radio-checked) .radio-inner {
  transform: rotate(45deg);

  border-width: $radio-ios-icon-border-width;
  border-top-width: 0;
  border-left-width: 0;
  border-style: $radio-ios-icon-border-style;
  border-color: var(--color-checked);
}

// iOS Radio: Disabled
// -----------------------------------------
// The radio and label should use the
// same opacity and match the other form
// controls

:host(.radio-disabled) {
  opacity: $radio-ios-disabled-opacity;
}

// iOS Radio: Keyboard Focus
// -----------------------------------------

:host(.ion-focused) .radio-icon::after {
  @include border-radius(var(--inner-border-radius));
  @include position(-8px, null, null, -9px);

  display: block;
  position: absolute;

  width: 36px;
  height: 36px;

  background: $radio-ios-background-color-focused;

  content: "";
  opacity: 0.2;
}

// Radio Native Wrapper
// ----------------------------------------------------------------

.native-wrapper .radio-icon {
  width: $radio-ios-icon-width;
  height: $radio-ios-icon-height;
}

@import "./toolbar";
@import "./toolbar.md.vars";

// Material Design Toolbar
// --------------------------------------------------

:host {
  --background: #{$toolbar-md-background};
  --color: #{$toolbar-md-color};
  --border-color: #{$toolbar-md-border-color};
  --padding-top: 0;
  --padding-bottom: 0;
  --padding-start: 0;
  --padding-end: 0;
  --min-height: 56px;
}


// Toolbar: Content
// --------------------------------------------------

.toolbar-content {
  flex: 1;
  order: map-get($toolbar-order-md, content);

  min-width: 0;
  max-width: 100%;
}

// Material Design Toolbar Buttons
// --------------------------------------------------

// Style the first slot with additional margin start
// this only ever gets added to the first start slot buttons
::slotted(.buttons-first-slot) {
  @include margin-horizontal(4px, null);
}

// Style the last slot with additional margin end
// this is added to the end, primary, or secondary slot
// whichever it finds first, and the first one it finds
// if multiple of the same name are found
::slotted(.buttons-last-slot) {
  @include margin-horizontal(null, 4px);
}


// Material Design Toolbar Slot Placement
// --------------------------------------------------

::slotted([slot="start"]) {
  order: map-get($toolbar-order-md, slot-start);
}

::slotted([slot="secondary"]) {
  order: map-get($toolbar-order-md, slot-secondary);
}

::slotted([slot="primary"]) {
  order: map-get($toolbar-order-md, slot-primary);

  text-align: end;
}

::slotted([slot="end"]) {
  order: map-get($toolbar-order-md, slot-end);

  text-align: end;
}

// TODO: Make better structure
:root {
  --bagde-height: 22px;
}

span.badge {
  min-width: 3rem;
  padding: 0 6px;
  margin-left: 14px;
  text-align: center;
  font-size: 1rem;
  line-height: var(--bagde-height);
  height: var(--bagde-height);
  color: var(--md-sys-color-on-surface-variant);
  float: right;
  box-sizing: border-box;

  &.new {
    font-weight: 300;
    font-size: 0.8rem;
    color: var(--md-sys-color-on-primary);
    background-color: var(--md-sys-color-primary);
    border-radius: 2px;
  }
  &.new:after {
    content: ' new';
  }

  &[data-badge-caption]::after {
    content: ' ' attr(data-badge-caption);
  }
}

.active span.badge {
  color: var(--md-sys-color-on-primary);
}

// Special cases

.navbar ul a span.badge {
  display: inline-block;
  float: none;
  margin-left: 4px;
  line-height: var(--bagde-height);
  height: var(--bagde-height);
  -webkit-font-smoothing: auto;
}

// Line height centering
.collection-item span.badge {
  margin-top: calc(calc(1.5rem * 0.5) - calc(var(--bagde-height) * 0.5));
}

.collapsible span.badge {
  margin-left: auto;

  &.leading {
    margin-right: 7px;
    order: -1;
  }
}

.collapsible .active span.badge:not(.new) {
  color: var(--md-sys-color-on-surface-variant);
}

.sidenav span.badge {
  margin-top: calc(calc(var(--sidenav-line-height) * 0.5) - calc(22px * 0.5));
}

table span.badge {
  display: inline-block;
  float: none;
  margin-left: auto;
}

//
// Browser
//
.browser {
  @include border-radius(var(--#{$prefix}border-radius-lg));
  box-shadow: 0 0 0 1px var(--#{$prefix}border-color);
  background: var(--#{$prefix}bg-surface-secondary);
  overflow: hidden;
}

.browser-header {
  padding: 0.25rem 1rem;
  background: var(--#{$prefix}border-color-light) linear-gradient(to bottom, rgba(0, 0, 0, 0), rgba(0, 0, 0, 0.03));
  border-bottom: 1px solid var(--#{$prefix}border-color);
  @include border-radius(calc(var(--#{$prefix}border-radius-lg) - 1px) calc(var(--#{$prefix}border-radius-lg) - 1px) 0 0);
}

.browser-dots {
  margin-inline-end: 3rem;
  display: flex;
}

.browser-dots-colored {
  .browser-dot {
    &:nth-child(1) {
      background: #fb6058;
    }

    &:nth-child(2) {
      background: #fcbe3b;
    }

    &:nth-child(3) {
      background: #2ccb4c;
    }
  }
}

.browser-dot {
  margin-inline-end: 0.5rem;
  width: 0.75rem;
  min-width: 0.75rem;
  height: 0.75rem;
  background: var(--#{$prefix}border-color);
  @include border-radius(var(--#{$prefix}border-radius-circle));
  border: 1px solid var(--#{$prefix}border-color-dark);
}

.browser-input {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  text-decoration: none;
  padding: 0.25rem;
  color: var(--#{$prefix}secondary);
  font-size: var(--#{$prefix}font-size-h5);
  @include border-radius(var(--#{$prefix}border-radius));
  line-height: 1;
  cursor: pointer;
  box-shadow:
    0 0 0 1px rgba(0, 0, 0, 0.05),
    0 1px 2px 0 rgba(0, 0, 0, 0.05);
  background-image: linear-gradient(to bottom, var(--#{$prefix}bg-surface), var(--#{$prefix}bg-surface-secondary));

  &:hover {
    text-decoration: none;
  }
}

@mixin hook-inverse-component-heading(){

    .uk-heading-small {
        @if(meta.mixin-exists(hook-inverse-heading-small)) {@include hook-inverse-heading-small();}
    }

    .uk-heading-medium {
